#include<bits/stdc++.h>
using namespace std;
int v[1000001][4],n,m,ans;
int main(){
    cin>>n>>m;
    for(int i=1;i<=m;i++){
        int l,r,x;
        cin>>l>>r>>x;
        v[r+1][x]-=1;
        v[l][x]+=1;


    }

    for(int i=1;i<=3;i++) for(int j=1;j<=n;j++) v[j][i]=v[j-1][i]+v[j][i];
    for(int i=1;i<=n;i++) if(v[i][1]>=1&&v[i][2]>=1&&v[i][3]<1) ans++;
    cout<<ans;
    return 0;
}
